/**
 * Validation helper module.
 *
 * Each exported function returns an array of error strings.
 * An empty array means all checks passed.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validates that `value` is a finite integer (or a string that parses to one).
 * Used for route-param / query-param ids.
 */
function validateId(value, fieldName = 'id') {
  const errors = [];
  const num = Number(value);
  if (value === undefined || value === null || value === '') {
    errors.push(`'${fieldName}' is required`);
  } else if (!Number.isFinite(num) || !Number.isInteger(num)) {
    errors.push(`'${fieldName}' must be a numeric integer (received: ${JSON.stringify(value)})`);
  } else if (num <= 0) {
    errors.push(`'${fieldName}' must be a positive integer`);
  }
  return errors;
}

/**
 * Validates a name field:
 *   - required
 *   - must be a string
 *   - length 1–100 characters
 */
function validateName(value, fieldName = 'name') {
  const errors = [];
  if (value === undefined || value === null) {
    errors.push(`'${fieldName}' is required`);
    return errors; // no point running further checks
  }
  if (typeof value !== 'string') {
    errors.push(`'${fieldName}' must be a string (received: ${typeof value})`);
    return errors;
  }
  if (value.length < 1) {
    errors.push(`'${fieldName}' must be at least 1 character long`);
  }
  if (value.length > 100) {
    errors.push(`'${fieldName}' must be at most 100 characters long (received: ${value.length})`);
  }
  return errors;
}

/**
 * Validates an email field:
 *   - required
 *   - must be a string
 *   - must match a basic email pattern
 *   - max 254 characters (RFC 5321)
 */
function validateEmail(value, fieldName = 'email') {
  const errors = [];
  if (value === undefined || value === null) {
    errors.push(`'${fieldName}' is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`'${fieldName}' must be a string (received: ${typeof value})`);
    return errors;
  }
  if (value.length > 254) {
    errors.push(`'${fieldName}' must be at most 254 characters long (received: ${value.length})`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`'${fieldName}' must be a valid email address (received: ${JSON.stringify(value)})`);
  }
  return errors;
}

/**
 * Validates the body for creating a user (POST /users).
 * Both 'name' and 'email' are required.
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validates the body for updating a user (PUT /users/:id).
 * At least one of 'name' or 'email' must be present; present fields
 * are fully validated.
 */
function validateUpdateUser(body) {
  const errors = [];
  const hasName = body.name !== undefined && body.name !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push("request body must include at least one of: 'name', 'email'");
    return errors;
  }
  if (hasName) errors.push(...validateName(body.name));
  if (hasEmail) errors.push(...validateEmail(body.email));
  return errors;
}

/**
 * Convenience middleware factory.
 * Pass a validator function; if it returns errors a 400 is sent automatically.
 *
 * Usage:
 *   app.post('/users', parseJson, validate(req => validateCreateUser(req.body)), handler)
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const errors = validatorFn(req);
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validate,
};

