/**
 * validation.js
 * Reusable input-validation helpers.
 *
 * Each validator returns an array of error strings (empty = valid).
 * collectErrors() merges multiple validator results and can be used
 * directly in route handlers.
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators – each returns [] or [errorMessage]
// ---------------------------------------------------------------------------

/**
 * Assert that a field is present (not undefined, null, or empty string).
 */
function required(value, fieldName) {
  if (value === undefined || value === null || value === '') {
    return [`${fieldName} is required`];
  }
  return [];
}

/**
 * Assert that a value, when coerced, is a finite integer > 0.
 * Accepts numeric strings ("42") as well as real numbers.
 */
function isNumericId(value, fieldName) {
  const num = Number(value);
  if (!Number.isFinite(num) || !Number.isInteger(num) || num <= 0) {
    return [`${fieldName} must be a positive integer`];
  }
  return [];
}

/**
 * Assert that a value is a non-empty string.
 */
function isString(value, fieldName) {
  if (typeof value !== 'string') {
    return [`${fieldName} must be a string`];
  }
  return [];
}

/**
 * Assert string length is within [min, max] (inclusive).
 * Skips the check when the value is not a string (pair with isString).
 */
function stringLength(value, fieldName, min, max) {
  if (typeof value !== 'string') return [];
  if (value.length < min || value.length > max) {
    return [`${fieldName} must be between ${min} and ${max} characters`];
  }
  return [];
}

/**
 * Assert that a value matches a basic RFC-5321-compatible e-mail pattern
 * and does not exceed 254 characters (the SMTP maximum).
 */
function isEmail(value, fieldName) {
  if (typeof value !== 'string') return [];          // isString covers type

  // Simple but robust pattern: local@domain.tld
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    return [`${fieldName} must be a valid email address`];
  }
  if (value.length > 254) {
    return [`${fieldName} must not exceed 254 characters`];
  }
  return [];
}

// ---------------------------------------------------------------------------
// Composite helpers used by route handlers
// ---------------------------------------------------------------------------

/**
 * Merge the results of multiple validator calls into a single array.
 *
 * Usage:
 *   const errors = collectErrors(
 *     required(body.name, 'name'),
 *     isString(body.name, 'name'),
 *     stringLength(body.name, 'name', 1, 100),
 *   );
 */
function collectErrors(...results) {
  return results.flat();
}

/**
 * Validate a user-creation / user-update payload.
 * `options.requireAll` – when true every field is mandatory (POST).
 *                       – when false only supplied fields are validated (PUT).
 */
function validateUserBody(body, { requireAll = true } = {}) {
  const errors = [];

  // ── name ────────────────────────────────────────────────────────────────
  if (requireAll || body.name !== undefined) {
    errors.push(...required(body.name, 'name'));
    errors.push(...isString(body.name, 'name'));
    errors.push(...stringLength(body.name, 'name', 1, 100));
  }

  // ── email ────────────────────────────────────────────────────────────────
  if (requireAll || body.email !== undefined) {
    errors.push(...required(body.email, 'email'));
    errors.push(...isString(body.email, 'email'));
    errors.push(...isEmail(body.email, 'email'));
    // Length check: max 254 already inside isEmail, but kept explicit too
    errors.push(...stringLength(body.email, 'email', 1, 254));
  }

  return errors;
}

/**
 * Validate a URL / route :id parameter.
 */
function validateIdParam(id) {
  return collectErrors(
    required(id, 'id'),
    isNumericId(id, 'id'),
  );
}

/**
 * Send a 400 response with a structured error payload.
 * Returns true so callers can do:  if (sendValidationError(res, errors)) return;
 */
function sendValidationError(res, errors) {
  if (!errors || errors.length === 0) return false;
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Primitives (useful for custom endpoint logic)
  required,
  isNumericId,
  isString,
  stringLength,
  isEmail,
  // Helpers
  collectErrors,
  validateUserBody,
  validateIdParam,
  sendValidationError,
};

