const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user `id` coming from a URL parameter.
 *   - Must be present
 *   - Must be a whole number (numeric string or actual number)
 *
 * @param {*} id - The raw value to validate
 * @returns {string[]} Array of validation error messages
 */
function validateUserId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors; // further checks are meaningless
  }

  const numeric = Number(id);
  if (!Number.isInteger(numeric) || numeric <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate user fields supplied in a request body.
 *
 * Rules:
 *   name  – required, must be a string, 1–100 characters
 *   email – required, must be a string, valid email format, max 254 characters
 *
 * @param {object} body          - The parsed request body
 * @param {object} [options]
 * @param {boolean} [options.requireAll=true] - When false, only validate fields
 *   that are actually present (useful for PATCH-style partial updates).
 * @returns {string[]} Array of validation error messages
 */
function validateUserBody(body, { requireAll = true } = {}) {
  const errors = [];
  const { name, email } = body || {};

  // ── name ──────────────────────────────────────────────────────────────────
  if (name === undefined || name === null) {
    if (requireAll) errors.push('name is required');
  } else {
    if (typeof name !== 'string') {
      errors.push('name must be a string');
    } else {
      if (name.trim().length === 0) {
        errors.push('name must not be empty (min 1 character)');
      } else if (name.length > 100) {
        errors.push('name must be 100 characters or fewer');
      }
    }
  }

  // ── email ─────────────────────────────────────────────────────────────────
  if (email === undefined || email === null) {
    if (requireAll) errors.push('email is required');
  } else {
    if (typeof email !== 'string') {
      errors.push('email must be a string');
    } else {
      if (email.length > 254) {
        errors.push('email must be 254 characters or fewer');
      }
      if (!EMAIL_REGEX.test(email)) {
        errors.push('email must be a valid email address');
      }
    }
  }

  return errors;
}

/**
 * Convenience: send a 400 response with a structured error payload.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 */
function sendValidationError(res, errors) {
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

module.exports = { validateUserId, validateUserBody, sendValidationError };

