const express = require('express');
const { validateUserId, validateUserBody, sendValidationError } = require('./validation');

const app = express();
app.use(express.json());

// ---------------------------------------------------------------------------
// In-memory "database" (seed data)
// ---------------------------------------------------------------------------
let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob',   email: 'bob@example.com'   },
];
let nextId = 3;

// ---------------------------------------------------------------------------
// GET /health  – no input; no validation needed
// ---------------------------------------------------------------------------
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// ---------------------------------------------------------------------------
// GET /users  – list all users; no input; no validation needed
// ---------------------------------------------------------------------------
app.get('/users', (req, res) => {
  res.json(users);
});

// ---------------------------------------------------------------------------
// POST /users  – create a new user
//
// Required body fields: name (string, 1–100 chars), email (string, valid, ≤254)
// ---------------------------------------------------------------------------
app.post('/users', (req, res) => {
  const errors = validateUserBody(req.body, { requireAll: true });
  if (errors.length) return sendValidationError(res, errors);

  const user = { id: nextId++, name: req.body.name, email: req.body.email };
  users.push(user);
  res.status(201).json(user);
});

// ---------------------------------------------------------------------------
// GET /users/:id  – fetch a single user
//
// Required param: id (positive integer)
// ---------------------------------------------------------------------------
app.get('/users/:id', (req, res) => {
  const idErrors = validateUserId(req.params.id);
  if (idErrors.length) return sendValidationError(res, idErrors);

  const user = users.find((u) => u.id === Number(req.params.id));
  if (!user) return res.status(404).json({ error: `User with id ${req.params.id} not found` });

  res.json(user);
});

// ---------------------------------------------------------------------------
// PUT /users/:id  – replace an existing user
//
// Required param : id (positive integer)
// Required body  : name (string, 1–100 chars), email (string, valid, ≤254)
// ---------------------------------------------------------------------------
app.put('/users/:id', (req, res) => {
  const errors = [
    ...validateUserId(req.params.id),
    ...validateUserBody(req.body, { requireAll: true }),
  ];
  if (errors.length) return sendValidationError(res, errors);

  const index = users.findIndex((u) => u.id === Number(req.params.id));
  if (index === -1) return res.status(404).json({ error: `User with id ${req.params.id} not found` });

  users[index] = { id: Number(req.params.id), name: req.body.name, email: req.body.email };
  res.json(users[index]);
});

// ---------------------------------------------------------------------------
// DELETE /users/:id  – remove a user
//
// Required param: id (positive integer)
// ---------------------------------------------------------------------------
app.delete('/users/:id', (req, res) => {
  const idErrors = validateUserId(req.params.id);
  if (idErrors.length) return sendValidationError(res, idErrors);

  const index = users.findIndex((u) => u.id === Number(req.params.id));
  if (index === -1) return res.status(404).json({ error: `User with id ${req.params.id} not found` });

  const [deleted] = users.splice(index, 1);
  res.json({ message: 'User deleted', user: deleted });
});

// ---------------------------------------------------------------------------

