// validation.js - reusable input validation helpers

/**
 * Validates that all required fields are present (not undefined, null, or empty string).
 * Returns an array of error messages (empty if all pass).
 */
function validateRequired(fields, body) {
  const errors = [];
  for (const field of fields) {
    if (body[field] === undefined || body[field] === null || body[field] === '') {
      errors.push(`'${field}' is required`);
    }
  }
  return errors;
}

/**
 * Validates that 'id' (from req.params or body) is a positive integer.
 */
function validateId(id) {
  const errors = [];
  const parsed = Number(id);
  if (!Number.isInteger(parsed) || parsed <= 0) {
    errors.push(`'id' must be a positive integer`);
  }
  return errors;
}

/**
 * Validates that 'name' is a non-empty string between 1 and 100 characters.
 * Only validates if the value is present (use validateRequired separately for presence).
 */
function validateName(name) {
  const errors = [];
  if (name === undefined || name === null) return errors; // absence handled by validateRequired
  if (typeof name !== 'string') {
    errors.push(`'name' must be a string`);
    return errors;
  }
  if (name.length < 1 || name.length > 100) {
    errors.push(`'name' must be between 1 and 100 characters`);
  }
  return errors;
}

/**
 * Validates that 'email' is a string matching a standard email format
 * and is at most 254 characters.
 * Only validates if the value is present.
 */
function validateEmail(email) {
  const errors = [];
  if (email === undefined || email === null) return errors; // absence handled by validateRequired
  if (typeof email !== 'string') {
    errors.push(`'email' must be a string`);
    return errors;
  }
  if (email.length > 254) {
    errors.push(`'email' must be at most 254 characters`);
  }
  // RFC-5321-inspired regex: local@domain.tld
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(email)) {
    errors.push(`'email' must be a valid email address`);
  }
  return errors;
}

/**
 * Runs a list of validator functions and combines their errors.
 * Each validator must return an array of error strings.
 */
function runValidators(...validators) {
  return validators.flatMap((v) => v());
}

/**
 * Express middleware factory — validates a request and sends a 400 response
 * listing all failures if any are found.
 *
 * Usage:
 *   router.post('/users', validate((req) => [
 *     ...validateRequired(['name', 'email'], req.body),
 *     ...validateName(req.body.name),
 *     ...validateEmail(req.body.email),
 *   ]), handler);
 */
function validate(getErrors) {
  return (req, res, next) => {
    const errors = getErrors(req);
    if (errors.length > 0) {
      return res.status(400).json({ error: 'Validation failed', details: errors });
    }
    next();
  };
}

module.exports = {
  validateRequired,
  validateId,
  validateName,
  validateEmail,
  runValidators,
  validate,
};

