  const numeric = Number(id);
  if (!Number.isInteger(numeric) || numeric <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a `name` field from a request body.
 *  - Required
 *  - Must be a string
 *  - Length: 1–100 characters
 */
function validateName(name, { required = true } = {}) {
  const errors = [];

  if (name === undefined || name === null) {
    if (required) errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  const trimmed = name.trim();
  if (trimmed.length < 1) {
    errors.push('name must be at least 1 character');
  } else if (trimmed.length > 100) {
    errors.push('name must be at most 100 characters');
  }

  return errors;
}

/**
 * Validate an `email` field from a request body.
 *  - Required
 *  - Must be a string
 *  - Must match email format
 *  - Max 254 characters (RFC 5321)
 */
function validateEmail(email, { required = true } = {}) {
  const errors = [];

  if (email === undefined || email === null) {
    if (required) errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.length > 254) {
    errors.push('email must be at most 254 characters');
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate the body of a POST /users request.
 * Both `name` and `email` are required.
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name, { required: true }),
    ...validateEmail(body.email, { required: true }),
  ];
}

/**
 * Validate the body of a PUT /users/:id request.
 * At least one of `name` or `email` must be provided;
 * whichever fields are present are fully validated.
 */
function validateUpdateUser(body) {
  const errors = [];

  const hasName = body.name !== undefined && body.name !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name, email) must be provided for update');
    return errors;
  }

  if (hasName) {
    errors.push(...validateName(body.name, { required: true }));
  }

  if (hasEmail) {
    errors.push(...validateEmail(body.email, { required: true }));
  }

  return errors;
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
};

